@font-face {
  font-family: 'MyCustomFont';
  src: url('/fonts/mycustomfont.woff2') format('woff2');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* Or 'block', 'fallback', 'optional' */
}

/* Apply the font to a critical element */
h1 {
  font-family: 'MyCustomFont', sans-serif;
  font-size: 2.5em;
  line-height: 1.2;
}
